from flask import Flask, request, jsonify
import jwt

class JWTManager:
    def __init__(self, secret_key=None, public_key=None):
        self.secret_key = secret_key
        self.public_key = public_key

    def encode(self, data, algorithm='HS256'):
        return jwt.encode(data, self.secret_key if algorithm == 'HS256' else self.public_key, algorithm=algorithm)

    def decode(self, token):
        try:
            # Attempt to decode with HS256 first
            return jwt.decode(token, self.secret_key, algorithms=['HS256'])
        except jwt.ExpiredSignatureError:
            pass  # Ignore, it might be an RS256 token
        except jwt.InvalidTokenError:
            raise ValueError("Invalid Token")

        # Attempt to decode with RS256
        try:
            return jwt.decode(token, self.public_key, algorithms=['RS256'])
        except jwt.InvalidTokenError:
            raise ValueError("Invalid Token")

app = Flask(__name__)
jwt_manager = JWTManager(secret_key="your_hs256_secret", public_key="your_rs256_public_key")

@app.route('/token', methods=['POST'])
def create_token():
    data = request.json
    algorithm = data.get('algorithm', 'HS256')
    token = jwt_manager.encode(data, algorithm)
    return jsonify({'token': token})

@app.route('/verify', methods=['POST'])
def verify_token():
    token = request.json.get('token')
    try:
        payload = jwt_manager.decode(token)
        return jsonify({'payload': payload}), 200
    except ValueError as e:
        return jsonify({'error': str(e)}), 401

if __name__ == '__main__':
    app.run()